.wordpress.org/starbuck/\">Tony G</a> · <a href=\"https://profiles.wordpress.org/hellofromtonya/\">Tonya Mork</a> · <a href=\"https://profiles.wordpress.org/toro_unit/\">Toro_Unit (Hiroshi Urabe)</a> · <a href=\"https://profiles.wordpress.org/zodiac1978/\">Torsten Landsiedel</a> · <a href=\"https://profiles.wordpress.org/tremidkhar/\">Tremi Dkhar</a> · <a href=\"https://profiles.wordpress.org/truptikanzariya/\">Trupti Kanzariya</a> · <a href=\"https://profiles.wordpress.org/tunetheweb/\">tunetheweb</a> · <a href=\"https://profiles.wordpress.org/twstokes/\">twstokes</a> · <a href=\"https://profiles.wordpress.org/tybor/\">tybor</a> · <a href=\"https://profiles.wordpress.org/u451f/\">u451f</a> · <a href=\"https://profiles.wordpress.org/ugyensupport/\">Ugyen Dorji</a> · <a href=\"https://profiles.wordpress.org/umesh84/\">Umesh Gupta</a> · <a href=\"https://profiles.wordpress.org/up1512001/\">up1512001</a> · <a href=\"https://profiles.wordpress.org/eboxnet/\">Vagelis</a> · <a href=\"https://profiles.wordpress.org/valer1eg/\">Val&#233;rie Galassi</a> · <a href=\"https://profiles.wordpress.org/vcanales/\">Vicente Canales</a> · <a href=\"https://profiles.wordpress.org/szepeviktor/\">Viktor Sz&#233;pe</a> · <a href=\"https://profiles.wordpress.org/vineet2003/\">Vinit</a> · <a href=\"https://profiles.wordpress.org/vinita29/\">Vinita Tandulkar</a> · <a href=\"https://profiles.wordpress.org/vipulgupta003/\">Vipul Gupta</a> · <a href=\"https://profiles.wordpress.org/ashokrane/\">Vishal Kothari</a> · <a href=\"https://profiles.wordpress.org/vivekawsm/\">vivekawsm</a> · <a href=\"https://profiles.wordpress.org/vrrobz/\">vrrobz</a> · <a href=\"https://profiles.wordpress.org/webmandesign/\">WebMan Design &#124; Oliver Juhas</a> · <a href=\"https://profiles.wordpress.org/websitegenii/\">websitegenii</a> · <a href=\"https://profiles.wordpress.org/wesatintellitonic/\">wesatintellitonic</a> · <a href=\"https://profiles.wordpress.org/westonruter/\">Weston Ruter</a> · <a href=\"https://profiles.wordpress.org/whaze/\">whaze</a> · <a href=\"https://profiles.wordpress.org/skorasaurus/\">Will Skora</a> · <a href=\"https://profiles.wordpress.org/earnjam/\">William Earnhardt</a> · <a href=\"https://profiles.wordpress.org/nestea29950/\">WilliamG</a> · <a href=\"https://profiles.wordpress.org/wojtekn/\">Wojtek Naruniec</a> · <a href=\"https://profiles.wordpress.org/wpsoul/\">wpsoul</a> · <a href=\"https://profiles.wordpress.org/yagniksangani/\">Yagnik Sangani</a> · <a href=\"https://profiles.wordpress.org/yankiara/\">yankiara</a> · <a href=\"https://profiles.wordpress.org/collet/\">Yann</a> · <a href=\"https://profiles.wordpress.org/yguyon/\">Yannis Guyon</a> · <a href=\"https://profiles.wordpress.org/fierevere/\">Yui</a> · <a href=\"https://profiles.wordpress.org/yukinobu/\">Yukinobu Asakawa</a> · <a href=\"https://profiles.wordpress.org/yuvrajsinh2211/\">Yuvrajsinh Sisodiya</a> · <a href=\"https://profiles.wordpress.org/zackkrida/\">Zack Krida</a> · <a href=\"https://profiles.wordpress.org/zackkatz/\">zackkatz</a> · <a href=\"https://profiles.wordpress.org/zafarkamal/\">Zafar Kamal</a> · <a href=\"https://profiles.wordpress.org/zeelthakkar/\">zeelthakkar</a> · <a href=\"https://profiles.wordpress.org/zenaulislam/\">Zenaul Islam</a> · <a href=\"https://profiles.wordpress.org/zieladam/\">zieladam</a> · <a href=\"https://profiles.wordpress.org/zkarj/\">zkarj</a> · <a href=\"https://profiles.wordpress.org/zunaid321/\">Zunaid Amin</a></p>\n\n\n\n<p>Mais de 60 localidades traduziram 90% ou mais do WordPress 6.6 para seu idioma. Os tradutores da comunidade estão trabalhando duro para garantir que mais traduções estejam a caminho. Agradecemos a todos que ajudam a disponibilizar o WordPress em 200 idiomas.</p>\n\n\n\n<p>Por último, mas não menos importante, agradecemos aos voluntários que contribuem com os fóruns de suporte respondendo a perguntas de usuários do WordPress em todo o mundo.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Envolva-se</h2>\n\n\n\n<p>A participação no WordPress vai muito além da codificação, e aprender mais e se envolver é fácil. Descubra as equipes que se reúnem para <a href=\"https://make.wordpress.org/\">fazer o WordPress</a> e use <a href=\"https://make.wordpress.org/contribute/\">esta ferramenta interativa</a> para ajudá-lo a decidir qual é o certo para você.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3088\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"WordPress 6.6 Release Candidate 3\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"https://br.wordpress.org/2024/07/10/wordpress-6-6-release-candidate-3/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 10 Jul 2024 20:31:58 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:12:\"Lançamentos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.6\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3086\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:334:\"O terceiro release candidate (RC3) para WordPress 6.6 está pronto para baixar e testar! Esta versão do software WordPress está em desenvolvimento. Por favor, não instale, execute ou teste esta versão do WordPress em sites de produção ou de missão crítica. Em vez disso, avalie o RC3 em um servidor de teste ou em um [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Andre Ribeiro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:9428:\"\n<p>O terceiro release candidate (RC3) para WordPress 6.6 está pronto para baixar e testar!</p>\n\n\n\n<p><strong>Esta versão do software WordPress está em desenvolvimento</strong>. <strong>Por favor, não instale, execute ou teste esta versão do WordPress em sites de produção ou de missão crítica.</strong> Em vez disso, avalie o RC3 em um servidor de teste ou em um ambiente local.</p>\n\n\n\n<p>Alcançar esta fase do ciclo de lançamento é um marco importante. Embora os release candidate sejam considerados prontos para lançamento, os testes continuam vitais para garantir que tudo no WordPress 6.6 seja o melhor possível.</p>\n\n\n\n<p>Você pode testar o WordPress 6.6 RC3 de quatro maneiras:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><th>Plugin</th><td>Instale e ative o plugin <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> em uma instalação do WordPress. (Selecione o canal “Bleeding edge” e o fluxo “Beta/RC Only”).</td></tr><tr><th>Baixe diretamente</th><td>Baixe a <a href=\"https://wordpress.org/wordpress-6.6-RC3.zip\">versão RC3 (zip)</a> e instale em um site WordPress.</td></tr><tr><th>Linha de comando</th><td>Use este comando <a href=\"https://make.wordpress.org/cli/\">WP-CLI:</a><br><code>wp core update --version=6.6-RC3</code></td></tr><tr><th>WordPress Playground</th><td>Use uma <a href=\"https://playground.wordpress.net/#%7B%20%22preferredVersions%22:%20%7B%20%22php%22:%20%228.0%22,%20%22wp%22:%20%22beta%22%20%7D,%20%22features%22:%20%7B%20%22networking%22:%20true%20%7D,%20%22steps%22:%20[%20%7B%20%22step%22:%20%22login%22,%20%22username%22:%20%22admin%22,%20%22password%22:%20%22password%22%20%7D,%20%7B%20%22step%22:%20%22importFile%22,%20%22file%22:%20%7B%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/wpaccessibility/a11y-theme-unit-test/master/a11y-theme-unit-test-data.xml%22%20%7D%20%7D,%20%7B%20%22step%22:%20%22importFile%22,%20%22file%22:%20%7B%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/WordPress/theme-test-data/master/themeunittestdata.wordpress.xml%22%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22query-monitor%22%20%7D,%20%22options%22:%20%7B%20%22activate%22:%20false%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22create-block-theme%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22debug-bar%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22health-check%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22test-reports%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22user-switching%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D%20]%20%7D\">instância 6.6 RC3 no WordPress Playground</a> (disponível dentro de 35 minutos após o lançamento estar pronto) para testar o software diretamente no seu navegador sem a necessidade de um site ou configuração separada.</td></tr></tbody></table></figure>\n\n\n\n<p>A meta atual para o lançamento do WordPress 6.6 é <strong>16 de julho de 2024</strong>. Obtenha uma visão geral do <a href=\"https://make.wordpress.org/core/6-6/\">ciclo de lançamento da versão 6.6</a> e confira o <a href=\"https://make.wordpress.org/core/\">blog Make WordPress Core</a> para <a href=\"https://make.wordpress.org/core/tag/6-6/\">posts relacionados a versão 6.6</a> na próxima semana para obter mais detalhes.</p>\n\n\n\n<h2 class=\"wp-block-heading\">O que há no WordPress 6.6 RC3?</h2>\n\n\n\n<p>Graças aos seus testes e a muitos outros colaboradores até agora, esta versão inclui oito correções de erros para o editor e <a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=06%2F25%2F2024..07%2F01%2F2024&amp;milestone=6.6&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">18 tíquetes para o núcleo do WordPress</a>.</p>\n\n\n\n<p>Obtenha uma recapitulação dos recursos destacados do WordPress 6.6 no <a href=\"https://br.wordpress.org/2024/06/05/wordpress-6-6-beta-1/\">anúncio da versão Beta 1.</a> Para obter mais informações técnicas relacionadas a problemas resolvidos desde a versão RC2, você pode navegar pelos seguintes links:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/wp/6.6?since=2024-07-02&amp;until=2024-07-09\">Tíquetes do GitHub para a versão 6.6</a> desde 2 de julho</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=06%2F25%2F2024..07%2F01%2F2024&amp;milestone=6.6&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">Tíquetes fechados do Trac</a> desde 2 de julho</li>\n</ul>\n\n\n\n<p>Quer olhar mais profundamente para os detalhes e notas técnicas para esta versão? Você pode querer fazer sua primeira parada <a href=\"https://make.wordpress.org/core/2024/06/25/wordpress-6-6-field-guide/\">O Guia de Campo do WordPress 6.6</a>. Então, confira esta lista:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/core/2024/06/20/roster-of-design-tools-per-block-wordpress-6-6-edition/\">Listagem de ferramentas de design por bloco (edição WordPress 6.6)</a>.</li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/tag/dev-notes+6-6/\">Todas as notas para desenvolvedor relacionadas a versão 6.6</a>.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Como contribuir?</h2>\n\n\n\n<p>O WordPress é um software de código aberto possibilitado pela comunidade de pessoas que colaboram e contribuem para o seu desenvolvimento. Os recursos abaixo descrevem uma variedade de maneiras pelas quais você pode ajudar, independentemente de sua experiência técnica.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Envolva-se nos testes</h3>\n\n\n\n<p>Testar problemas é fundamental para garantir que o WordPress seja performante e estável. Também é uma maneira significativa de qualquer pessoa contribuir. <a href=\"https://make.wordpress.org/test/2024/06/03/help-test-wordpress-6-6/\">Este guia detalhado</a> irá orientá-lo através de recursos de teste no WordPress 6.6. Para aqueles que estão começando a testar, sigam <a href=\"https://make.wordpress.org/test/2024/06/03/help-test-wordpress-6-6/\">este guia de testes geral</a> para obter mais detalhes sobre como começar.</p>\n\n\n\n<p>Se você encontrar um problema, informe-o na <a href=\"https://wordpress.org/support/forum/alphabeta/\">área Alpha / Beta</a> dos fóruns de suporte ou diretamente ao <a href=\"https://core.trac.wordpress.org/newticket\">WordPress Trac</a> se você estiver confortável escrevendo um relatório de erros reprodutível. Você também pode verificar seu problema em relação a uma lista de <a href=\"https://core.trac.wordpress.org/tickets/major\">erros conhecidos</a>.</p>\n\n\n\n<p>Curioso sobre os testes de lançamentos em geral? Acompanhe as <a href=\"https://make.wordpress.org/test/\">iniciativas de teste</a> no <a href=\"https://make.wordpress.org/test/\">Make WordPress Core</a> e junte-se ao <a href=\"https://wordpress.slack.com/messages/core-test/\">canal #core-test</a> no <a href=\"https://wordpress.slack.com/\">Slack do WordPress</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Atualize seu tema ou plugin</h3>\n\n\n\n<p>Para autores de plugins e temas, seus produtos desempenham um papel fundamental na extensão da funcionalidade e valor do WordPress para todos os usuários.</p>\n\n\n\n<p>Agradecemos por continuar a testar seus temas e plugins com as versões beta do WordPress 6.6. Com o RC3, você vai querer concluir seus testes e atualizar a versão <em>“Tested up to”</em> no <a href=\"https://developer.wordpress.org/plugins/wordpress-org/how-your-readme-txt-works/\">arquivo readme</a> do seu <a href=\"https://developer.wordpress.org/plugins/wordpress-org/how-your-readme-txt-works/\">plugin</a> para a versão 6.6.</p>\n\n\n\n<p>Se você encontrar problemas de compatibilidade, publique informações detalhadas no <a href=\"https://wordpress.org/support/forum/alphabeta/\">fórum de suporte</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Traduza o WordPress</h2>\n\n\n\n<p><a href=\"https://translate.wordpress.org/projects/wp/dev/pt-br/default/\">Ajude-nos a traduzir o WordPress para o português!</a>&nbsp;O lançamento dessa versão também significa que&nbsp;<a href=\"https://make.wordpress.org/polyglots/handbook/glossary/#hard-freeze\">novas strings para a tradução</a>&nbsp;da versão 6.6 serão evitadas.</p>\n\n\n\n<p class=\"has-text-align-right\"><em>Agradecemos a <a href=\"https://profiles.wordpress.org/meher/\">@meher</a> e <a href=\"https://profiles.wordpress.org/audrasjb/\">@audrasjb</a> pela revisão.</em></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3086\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"WordPress 6.6 Release Candidate 2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"https://br.wordpress.org/2024/07/03/wordpress-6-6-release-candidate-2/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 03 Jul 2024 12:02:14 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:12:\"Lançamentos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.6\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3081\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:333:\"O segundo release candidate (RC2) para WordPress 6.6 está pronto para baixar e testar! Esta versão do software WordPress está em desenvolvimento. Por favor, não instale, execute ou teste esta versão do WordPress em sites de produção ou de missão crítica. Em vez disso, avalie o RC2 em um servidor de teste ou em um [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Andre Ribeiro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:10977:\"\n<p>O segundo release candidate (RC2) para WordPress 6.6 está pronto para baixar e testar!</p>\n\n\n\n<p><strong>Esta versão do software WordPress está em desenvolvimento</strong>. <strong>Por favor, não instale, execute ou teste esta versão do WordPress em sites de produção ou de missão crítica.</strong> Em vez disso, avalie o RC2 em um servidor de teste ou em um ambiente local.</p>\n\n\n\n<p>Alcançar esta fase do ciclo de lançamento é um marco importante. Embora os release candidate sejam considerados prontos para lançamento, os testes continuam vitais para garantir que tudo no WordPress 6.6 seja o melhor possível.</p>\n\n\n\n<p>Você pode testar o WordPress 6.6 RC2 de quatro maneiras:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><th>Plugin</th><td>Instale e ative o plugin <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> em uma instalação do WordPress. (Selecione o canal “Bleeding edge” e o fluxo “Beta/RC Only”).</td></tr><tr><th>Baixe diretamente</th><td>Baixe a <a href=\"https://wordpress.org/wordpress-6.6-RC2.zip\">versão RC2 (zip)</a> e instale em um site WordPress.</td></tr><tr><th>Linha de comando</th><td>Use este comando <a href=\"https://make.wordpress.org/cli/\">WP-CLI:</a><br><code>wp core update --version=6.6-RC2</code></td></tr><tr><th>WordPress Playground</th><td>Use uma <a href=\"https://playground.wordpress.net/#%7B%20%22preferredVersions%22:%20%7B%20%22php%22:%20%228.0%22,%20%22wp%22:%20%22beta%22%20%7D,%20%22features%22:%20%7B%20%22networking%22:%20true%20%7D,%20%22steps%22:%20[%20%7B%20%22step%22:%20%22login%22,%20%22username%22:%20%22admin%22,%20%22password%22:%20%22password%22%20%7D,%20%7B%20%22step%22:%20%22importFile%22,%20%22file%22:%20%7B%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/wpaccessibility/a11y-theme-unit-test/master/a11y-theme-unit-test-data.xml%22%20%7D%20%7D,%20%7B%20%22step%22:%20%22importFile%22,%20%22file%22:%20%7B%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/WordPress/theme-test-data/master/themeunittestdata.wordpress.xml%22%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22query-monitor%22%20%7D,%20%22options%22:%20%7B%20%22activate%22:%20false%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22create-block-theme%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22debug-bar%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22health-check%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22test-reports%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22user-switching%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D%20]%20%7D\">instância 6.6 RC2 no WordPress Playground</a> (disponível dentro de 35 minutos após o lançamento estar pronto) para testar o software diretamente no seu navegador sem a necessidade de um site ou configuração separada.</td></tr></tbody></table></figure>\n\n\n\n<p>A meta atual para o lançamento do WordPress 6.6 é <strong>16 de julho de 2024</strong>. Obtenha uma visão geral do <a href=\"https://make.wordpress.org/core/6-6/\">ciclo de lançamento da versão 6.6</a> e confira o <a href=\"https://make.wordpress.org/core/\">blog Make WordPress Core</a> para <a href=\"https://make.wordpress.org/core/tag/6-6/\">posts relacionados a versão 6.6</a> nas próximas semanas para obter mais detalhes.</p>\n\n\n\n<h2 class=\"wp-block-heading\">O que há no WordPress 6.6 RC2?</h2>\n\n\n\n<p>Graças aos seus testes e a muitos outros colaboradores até agora, esta versão inclui mais de 19 correções de erros para o editor e mais de <a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=06%2F25%2F2024..07%2F01%2F2024&amp;milestone=6.6&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">20 tíquetes para o núcleo do WordPress</a>.</p>\n\n\n\n<p>Obtenha uma recapitulação dos recursos destacados do WordPress 6.6 no <a href=\"https://br.wordpress.org/2024/06/05/wordpress-6-6-beta-1/\">anúncio da versão Beta 1.</a> Para obter mais informações técnicas relacionadas a problemas resolvidos desde a versão Beta 3, você pode navegar pelos seguintes links:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/wp/6.6?since=2024-06-24&amp;until=2024-06-30\">Tíquetes do GitHub para a versão 6.6</a> desde 25 de junho.</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=06%2F25%2F2024..07%2F01%2F2024&amp;milestone=6.6&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">Tíquetes fechados do Trac</a> desde 25 de junho.</li>\n</ul>\n\n\n\n<p>Quer olhar mais profundamente para os detalhes e notas técnicas para esta versão? Você pode começar conferindo o <a href=\"https://make.wordpress.org/core/2024/06/25/wordpress-6-6-field-guide/\">O Guia de Campo do WordPress 6.6</a>. Então, confira esta lista:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/core/2024/06/20/roster-of-design-tools-per-block-wordpress-6-6-edition/\">Listagem de ferramentas de design por bloco (edição WordPress 6.6)</a>.</li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2024/07/01/hallway-hangout-section-styles-and-other-block-style-variation-updates/\">Videoconferência: estilos de seção e outras atualizações de variação de estilo de bloco</a>.</li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2024/07/01/recap-hallway-hangout-exploring-grid-layouts/\">Recapitulação da Videoconferência: Explorando Layouts de Grade</a>.</li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2024/06/28/editing-custom-fields-from-connected-blocks/\">Editando campos personalizados de blocos conectados</a>.</li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2024/06/28/updates-to-the-interactivity-api-in-6-6/\">Atualizações para a API de Interatividade na versão 6.6</a>.</li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/tag/dev-notes+6-6/\">Todas as notas para desenvolvedor relacionadas a versão 6.6</a>.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Como contribuir?</h2>\n\n\n\n<p>O WordPress é um software de código aberto possibilitado pela comunidade de pessoas que colaboram e contribuem para o seu desenvolvimento. Os recursos abaixo descrevem uma variedade de maneiras pelas quais você pode ajudar, independentemente de sua experiência técnica.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Envolva-se nos testes</h3>\n\n\n\n<p>Testar problemas é fundamental para garantir que o WordPress seja performante e estável. Também é uma maneira significativa de qualquer pessoa contribuir. <a href=\"https://make.wordpress.org/test/2024/06/03/help-test-wordpress-6-6/\">Este guia detalhado</a> irá orientá-lo através de recursos de teste no WordPress 6.6. Para aqueles que estão começando a testar, sigam <a href=\"https://make.wordpress.org/test/2024/06/03/help-test-wordpress-6-6/\">este guia de testes geral</a> para obter mais detalhes sobre como começar.</p>\n\n\n\n<p>Se você encontrar um problema, informe-o na <a href=\"https://wordpress.org/support/forum/alphabeta/\">área Alpha / Beta</a> dos fóruns de suporte ou diretamente ao <a href=\"https://core.trac.wordpress.org/newticket\">WordPress Trac</a> se você estiver confortável escrevendo um relatório de erros reprodutível. Você também pode verificar seu problema em relação a uma lista de <a href=\"https://core.trac.wordpress.org/tickets/major\">erros conhecidos</a>.</p>\n\n\n\n<p>Curioso sobre os testes de lançamentos em geral? Acompanhe as <a href=\"https://make.wordpress.org/test/\">iniciativas de teste</a> no <a href=\"https://make.wordpress.org/test/\">Make WordPress Core</a> e junte-se ao <a href=\"https://wordpress.slack.com/messages/core-test/\">canal #core-test</a> no <a href=\"https://wordpress.slack.com/\">Slack do WordPress</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">A recompensa de vulnerabilidade dobra durante as versões Beta/RC</h3>\n\n\n\n<p>Durante a fase de lançamento do WordPress 6.6, a <a href=\"https://make.wordpress.org/security/2024/06/04/wordpress-6-6-is-coming/\">recompensa monetária por relatar novas vulnerabilidades de segurança não lançadas é dobrada</a>. Siga as práticas de divulgação responsável, conforme detalhado nas práticas e políticas de segurança do projeto descritas na <a href=\"https://hackerone.com/wordpress\">página do HackerOne</a> e no <a href=\"https://wordpress.org/about/security/\">white paper de segurança</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Atualize seu tema ou plugin</h3>\n\n\n\n<p>Para autores de plugins e temas, seus produtos desempenham um papel fundamental na extensão da funcionalidade e valor do WordPress para todos os usuários.</p>\n\n\n\n<p>Agradecemos por continuar a testar seus temas e plugins com as versões beta do WordPress 6.6. Com o RC2, você vai querer concluir seus testes e atualizar a versão <em>“Tested up to”</em> no <a href=\"https://developer.wordpress.org/plugins/wordpress-org/how-your-readme-txt-works/\">arquivo readme</a> do seu <a href=\"https://developer.wordpress.org/plugins/wordpress-org/how-your-readme-txt-works/\">plugin</a> para a versão 6.6.</p>\n\n\n\n<p>Se você encontrar problemas de compatibilidade, publique informações detalhadas no <a href=\"https://wordpress.org/support/forum/alphabeta/\">fórum de suporte</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Traduza o WordPress</h2>\n\n\n\n<p><a href=\"https://translate.wordpress.org/projects/wp/dev/pt-br/default/\">Ajude-nos a traduzir o WordPress para o português!</a>&nbsp;O lançamento dessa versão também significa que&nbsp;<a href=\"https://make.wordpress.org/polyglots/handbook/glossary/#hard-freeze\">novas strings para a tradução</a>&nbsp;da versão 6.6 serão evitadas.</p>\n\n\n\n<p class=\"has-text-align-right\"><em>Agradecemos a <a href=\"https://profiles.wordpress.org/juanmaguitar/\">@juanmaguitar</a>, <a href=\"https://profiles.wordpress.org/meher/\">@meher</a>, <a href=\"https://profiles.wordpress.org/desrosj/\">@desrosj</a></em> e<em> <a href=\"https://profiles.wordpress.org/atachibana/\">@atachibana</a> pela revisão.</em></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3081\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"WordPress 6.6 Release Candidate 1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"https://br.wordpress.org/2024/06/25/wordpress-6-6-release-candidate-1/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 25 Jun 2024 17:56:24 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:12:\"Lançamentos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.6\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3072\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:334:\"O primeiro release candidate (RC1) para WordPress 6.6 está pronto para baixar e testar! Esta versão do software WordPress está em desenvolvimento. Por favor, não instale, execute ou teste esta versão do WordPress em sites de produção ou de missão crítica. Em vez disso, avalie o RC1 em um servidor de teste ou em um [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Andre Ribeiro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:13450:\"\n<p>O primeiro release candidate (RC1) para WordPress 6.6 está pronto para baixar e testar!</p>\n\n\n\n<p><strong>Esta versão do software WordPress está em desenvolvimento</strong>. <strong>Por favor, não instale, execute ou teste esta versão do WordPress em sites de produção ou de missão crítica.</strong> Em vez disso, avalie o RC1 em um servidor de teste ou em um ambiente local.</p>\n\n\n\n<p>Alcançar esta fase do ciclo de lançamento é um marco importante. Embora os release candidates sejam considerados prontos para lançamento, os testes continuam vitais para garantir que tudo no WordPress 6.6 seja o melhor possível.</p>\n\n\n\n<p>Você pode testar o WordPress 6.6 RC1 de quatro maneiras:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><th>Plugin</th><td>Instale e ative o plugin <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> em uma instalação do WordPress. (Selecione o canal “Bleeding edge” e o fluxo “Beta/RC Only”).</td></tr><tr><th>Baixar diretamente</th><td>Baixe a <a href=\"https://wordpress.org/wordpress-6.6-RC1.zip\">versão RC1 (zip)</a> e instale-a em um site WordPress.</td></tr><tr><th>Linha de comando</th><td>Use este comando <a href=\"https://make.wordpress.org/cli/\">WP-CLI:</a><br><code>wp core update --version=6.6-RC1</code></td></tr><tr><th>WordPress Playground</th><td>Use a <a href=\"https://playground.wordpress.net/#%7B%20%22preferredVersions%22:%20%7B%20%22php%22:%20%228.0%22,%20%22wp%22:%20%22beta%22%20%7D,%20%22features%22:%20%7B%20%22networking%22:%20true%20%7D,%20%22steps%22:%20[%20%7B%20%22step%22:%20%22login%22,%20%22username%22:%20%22admin%22,%20%22password%22:%20%22password%22%20%7D,%20%7B%20%22step%22:%20%22importFile%22,%20%22file%22:%20%7B%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/wpaccessibility/a11y-theme-unit-test/master/a11y-theme-unit-test-data.xml%22%20%7D%20%7D,%20%7B%20%22step%22:%20%22importFile%22,%20%22file%22:%20%7B%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/WordPress/theme-test-data/master/themeunittestdata.wordpress.xml%22%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22query-monitor%22%20%7D,%20%22options%22:%20%7B%20%22activate%22:%20false%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22create-block-theme%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22debug-bar%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22health-check%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22test-reports%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22user-switching%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D%20]%20%7D\">instância</a> <a href=\"https://playground.wordpress.net/#%7B%20%22preferredVersions%22:%20%7B%20%22php%22:%20%228.0%22,%20%22wp%22:%20%22beta%22%20%7D,%20%22features%22:%20%7B%20%22networking%22:%20true%20%7D,%20%22steps%22:%20[%20%7B%20%22step%22:%20%22login%22,%20%22username%22:%20%22admin%22,%20%22password%22:%20%22password%22%20%7D,%20%7B%20%22step%22:%20%22importFile%22,%20%22file%22:%20%7B%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/wpaccessibility/a11y-theme-unit-test/master/a11y-theme-unit-test-data.xml%22%20%7D%20%7D,%20%7B%20%22step%22:%20%22importFile%22,%20%22file%22:%20%7B%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/WordPress/theme-test-data/master/themeunittestdata.wordpress.xml%22%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22query-monitor%22%20%7D,%20%22options%22:%20%7B%20%22activate%22:%20false%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22create-block-theme%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22debug-bar%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22health-check%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22test-reports%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D,%20%7B%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20%7B%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22user-switching%22%20%7D,%20%22progress%22:%20%7B%20%22weight%22:%202%20%7D%20%7D%20]%20%7D\">6.6 RC1 do WordPress Playground</a> (disponível dentro de 35 minutos após o lançamento estar pronto) para testar o software diretamente no seu navegador sem a necessidade de um site ou configuração separada.</td></tr></tbody></table></figure>\n\n\n\n<p>A meta atual para a versão final do WordPress 6.6 é <strong>16 de julho de 2024</strong>. Obtenha uma visão geral do <a href=\"https://make.wordpress.org/core/6-6/\">ciclo de lançamento da versão 6.6</a> e confira o <a href=\"https://make.wordpress.org/core/\">blog Make WordPress Core</a> para <a href=\"https://make.wordpress.org/core/tag/6-6/\">posts relacionados a versão 6.6 </a> nas próximas semanas para obter mais detalhes.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Duas notas sobre as mudanças no período RC</h2>\n\n\n\n<p><strong>Congelamento de strings para traduções:</strong> de agora até 16 de julho, há um <a href=\"https://make.wordpress.org/polyglots/handbook/glossary/#hard-freeze\">congelamento de strings</a>. Nenhuma string pode mudar e nenhuma nova cadeia pode ser confirmada. Isso é para dar as equipes de tradução um tempo para traduzir o WordPress 6.6 em tantos idiomas quanto possível antes do lançamento final.</p>\n\n\n\n<p><strong>Revisão de 2 contribuidores:</strong> Contribuições de código no período das versões RC requerem revisão de dois colaboradores em cada submissão. Como as versões RCs devem estar prontos para publicação, apenas as principais correções devem ser adicionadas ao núcleo.</p>\n\n\n\n<h2 class=\"wp-block-heading\">O que há no WordPress 6.6 RC1?</h2>\n\n\n\n<p>Graças aos seus testes e muitos outros colaboradores até agora, esta versão inclui mais de 40 correções de erros para o editor e mais de <a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=02%2F27%2F2024..03%2F05%2F2024&amp;milestone=6.5&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">40 tíquetes para o núcleo do WordPress</a>.</p>\n\n\n\n<p>Obtenha uma recapitulação dos recursos destacados do WordPress 6.6 no <a href=\"https://br.wordpress.org/2024/06/19/wordpress-6-6-beta-3/\">anúncio da versão Beta 1.</a> Para obter mais informações técnicas relacionadas a problemas resolvidos desde a versão Beta 3, você pode navegar pelos seguintes links:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/wp/6.6?since=2024-06-18&amp;until=2024-06-24\">Tíquetes do GitHub para a versão 6.6</a> desde 18 de junho.</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=06%2F18%2F24..06%2F24%2F2024&amp;milestone=6.6&amp;max=1000&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">Tíquetes fechados do Trac</a> desde 18 de junho.</li>\n</ul>\n\n\n\n<p>Quer olhar mais profundamente para os detalhes e notas técnicas para esta versão? Estes posts recentes cobrem algumas das atualizações mais recentes:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/core/2024/06/21/wordpress-6-6-css-specificity/\">Especificidade de CSS no WordPress 6.6</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2024/06/20/site-wide-background-images-in-wordpress-6-6/\">Imagens de fundo em todo o site no WordPress 6.6</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2024/06/24/section-styles/\">Estilos de Seção</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2024/06/20/roster-of-design-tools-per-block-wordpress-6-6-edition/\">Ferramentas de design por bloco no WordPress 6.6</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2024/06/25/wordpress-6-6-field-guide/\">Guia do WordPress 6.6</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/tag/dev-notes-6-6/\">Todas as notas de desenvolvedor relacionadas a versão 6.6</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Como contribuir?</h2>\n\n\n\n<p>O WordPress é um software de código aberto possibilitado pela comunidade de pessoas que colaboram e contribuem para o seu desenvolvimento. Os recursos abaixo descrevem uma variedade de maneiras pelas quais você pode ajudar, independentemente de sua experiência técnica.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Envolva-se nos testes</h3>\n\n\n\n<p>Testar problemas é fundamental para garantir que o WordPress seja performante e estável. Também é uma maneira significativa de qualquer pessoa contribuir. <a href=\"https://wordpress.org/news/2024/06/wordpress-6-6-beta-3/\">Este guia detalhado</a> irá orientá-lo através de recursos de teste no WordPress 6.6. Para aqueles que estão começando a testar, sigam <a href=\"https://wordpress.org/news/2024/06/wordpress-6-6-beta-1/\">este guia de testes geral</a> para obter mais detalhes sobre como começar.</p>\n\n\n\n<p>Se você encontrar um problema, informe-o na <a href=\"https://wordpress.org/support/forum/alphabeta/\">área Alpha / Beta</a> dos fóruns de suporte ou diretamente ao <a href=\"https://core.trac.wordpress.org/newticket\">WordPress Trac</a> se você estiver confortável escrevendo um relatório de erros reprodutível. Você também pode verificar seu problema em relação a uma lista de <a href=\"https://core.trac.wordpress.org/tickets/major\">erros conhecidos</a>.</p>\n\n\n\n<p>Curioso sobre os testes de lançamentos em geral? Acompanhe as <a href=\"https://make.wordpress.org/test/\">iniciativas de teste</a> no <a href=\"https://make.wordpress.org/test/\">Make WordPress Core</a> e junte-se ao <a href=\"https://wordpress.slack.com/messages/core-test/\">canal #core-test</a> no <a href=\"https://wordpress.slack.com/\">Slack do WordPress</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">A recompensa de vulnerabilidade dobra durante as versões Beta/RC</h3>\n\n\n\n<p>Durante a fase de lançamento do WordPress 6.6, a <a href=\"https://make.wordpress.org/security/2024/06/04/wordpress-6-6-is-coming/\">recompensa monetária por relatar novas vulnerabilidades de segurança não lançadas é dobrada</a>. Siga as práticas de divulgação responsável, conforme detalhado nas práticas e políticas de segurança do projeto descritas na <a href=\"https://hackerone.com/wordpress\">página do HackerOne</a> e no <a href=\"https://wordpress.org/about/security/\">white paper de segurança</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Atualize seu tema ou plugin</h3>\n\n\n\n<p>Para autores de plugins e temas, seus produtos desempenham um papel fundamental na extensão da funcionalidade e valor do WordPress para todos os usuários.</p>\n\n\n\n<p>Agradecemos por continuar a testar seus temas e plugins com as versões beta do WordPress 6.6. Com o RC1, você vai querer concluir seus testes e atualizar a versão <em>“Tested up to”</em> no <a href=\"https://developer.wordpress.org/plugins/wordpress-org/how-your-readme-txt-works/\">arquivo readme</a> do seu <a href=\"https://developer.wordpress.org/plugins/wordpress-org/how-your-readme-txt-works/\">plugin</a> para a versão 6.6.</p>\n\n\n\n<p>Se você encontrar problemas de compatibilidade, publique informações detalhadas no <a href=\"https://wordpress.org/support/forum/alphabeta/\">fórum de suporte</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Traduza o WordPress</h2>\n\n\n\n<p><a href=\"https://translate.wordpress.org/projects/wp/dev/pt-br/default/\">Ajude-nos a traduzir o WordPress para o português!</a>&nbsp;O lançamento dessa versão também significa que&nbsp;<a href=\"https://make.wordpress.org/polyglots/handbook/glossary/#hard-freeze\">novas strings para a tradução</a>&nbsp;da versão 6.6 serão evitadas.</p>\n\n\n\n<p class=\"has-text-align-right\"><em>Agradecemos a <a href=\"https://profiles.wordpress.org/meher/\">@meher</a>, <a href=\"https://profiles.wordpress.org/audrasjb/\">@audrasjb</a> por colaborar com este post.</em></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3072\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:47:\"WordPress 6.5.5 – Atualização de segurança\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"https://br.wordpress.org/2024/06/25/wordpress-6-5-5-atualizacao-de-seguranca/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 25 Jun 2024 12:16:51 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:12:\"Lançamentos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.5\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3069\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:390:\"O WordPress 6.5.5 já está disponível! Esta versão apresenta três correções de segurança. Como esta é uma versão de segurança, é recomendável que você atualize seus sites imediatamente. Esta versão também inclui 3 correções de erros no núcleo. Você pode baixar o WordPress 6.5.5 no WordPress.org ou visitar seu Painel WordPress, clicar em “Atualizações” e [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Andre Ribeiro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5369:\"\n<p>O WordPress 6.5.5 já está disponível!</p>\n\n\n\n<p>Esta versão apresenta três correções de segurança. Como esta é uma versão de segurança, <strong>é recomendável que você atualize seus sites imediatamente. </strong>Esta versão também inclui <a href=\"https://core.trac.wordpress.org/query?component=!Build%2FTest+Tools&amp;milestone=6.5.5&amp;col=id&amp;col=summary&amp;col=owner&amp;col=type&amp;col=status&amp;col=priority&amp;col=component&amp;order=priority\">3 correções de erros</a> no núcleo.</p>\n\n\n\n<p>Você pode <a href=\"https://wordpress.org/wordpress-6.5.5.zip\">baixar o WordPress 6.5.5 no WordPress.org</a> ou visitar seu Painel WordPress, clicar em “Atualizações” e clicar em “Atualizar agora”. Se você tiver sites que suportam atualizações automáticas em segundo plano, o processo de atualização será iniciado automaticamente.</p>\n\n\n\n<p>O WordPress 6.5.5 é uma versão de ciclo curto. O próximo grande lançamento será a versão 6.6, que está prevista para 16 de julho de 2024.</p>\n\n\n\n<p>Para mais informações sobre o WordPress 6.5.5, visite o <a href=\"https://wordpress.org/documentation/wordpress-version/version-6-5-5/\">site HelpHub</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Atualizações de segurança incluídas nesta versão</h2>\n\n\n\n<p>A equipe de segurança gostaria de agradecer às seguintes pessoas por <a href=\"https://hackerone.com/wordpress?type=team\">relatar vulnerabilidades de forma responsável</a> e permitir que elas sejam corrigidas nesta versão:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Uma vulnerabilidade de cross-site scripting (XSS) que afeta a API HTML relatada por Dennis Snell do time de núcleo do WordPress, juntamente com Alex Concha e Grzegorz (Greg) Ziókowski da equipe de segurança do WordPress.</li>\n\n\n\n<li>Uma vulnerabilidade de scripts entre sites (XSS) que afeta o bloco de partes de temas reportado independentemente por Rafie Muhammad da Patchstack e durante uma auditoria de segurança de terceiros.</li>\n\n\n\n<li>Um problema de encaminhamento que afeta sites hospedados no Windows relatados de forma independente por Rafie M &amp; Edouard L de Patchstack, David Fifield, <a href=\"https://hackerone.com/x89\">x89</a>, <a href=\"https://hackerone.com/apple502j\">apple502j</a> e <a href=\"https://hackerone.com/mishre\">mishre</a>.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Agradecimento aos colaboradores</h2>\n\n\n\n<p>Este lançamento foi liderado por <a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a>.</p>\n\n\n\n<p>O WordPress 6.5.5 não teria sido possível sem as contribuições das pessoas a seguir. Suas contribuições para fornecer correções de manutenção em uma versão estável é uma prova do poder e capacidade da comunidade WordPress.</p>\n\n\n\n<p><a href=\"https://profiles.wordpress.org/jorbin\">Aaron Jorbin</a>, <a href=\"https://profiles.wordpress.org/xknown\">Alex Concha</a>, <a href=\"https://profiles.wordpress.org/azaozz\">Andrew Ozz</a>, <a href=\"https://profiles.wordpress.org/bernhard-reiter\">bernhard-reiter</a>, <a href=\"https://profiles.wordpress.org/costdev\">Colin Stewart</a>, <a href=\"https://profiles.wordpress.org/davidbaumwald/\">David Baumwald</a>, <a href=\"https://profiles.wordpress.org/dmsnell\">Dennis Snell</a>, <a href=\"https://profiles.wordpress.org/grantmkin\">Grant M. Kinney</a>, <a href=\"https://profiles.wordpress.org/gziolo\">Greg Ziółkowski</a>, <a href=\"https://profiles.wordpress.org/audrasjb\">Jb Audras</a>, <a href=\"https://profiles.wordpress.org/desrosj\">Jonathan Desrosiers</a>, <a href=\"https://profiles.wordpress.org/matveb\">Matias Ventura</a>, <a href=\"https://profiles.wordpress.org/mcsf\">Miguel Fonseca</a>, <a href=\"https://profiles.wordpress.org/peterwilsoncc\">Peter Wilson</a>, <a href=\"https://profiles.wordpress.org/rajinsharwar\">Rajin Sharwar</a>, <a href=\"https://profiles.wordpress.org/coffee2code\">Scott Reilly</a> e <a href=\"https://profiles.wordpress.org/hellofromTonya\">Tonya Mork</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Como contribuir</h2>\n\n\n\n<p>Para se envolver no desenvolvimento do núcleo do WordPress, dirija-se ao Trac, <a href=\"https://core.trac.wordpress.org/report/6\">escolha um ticket</a> e participe da conversa nos canais <a href=\"https://wordpress.slack.com/archives/C02RQBWTW\">#core</a> e <a href=\"https://wordpress.slack.com/archives/C06U06K50Q5\">#6-6-release-leads</a>. Precisa de ajuda? Confira o <a href=\"https://make.wordpress.org/core/handbook/\">Manual do colaborador do núcleo</a>.</p>\n\n\n\n<p><em>Testando o WordPress 6.6? O quarto beta já está disponível (<a href=\"https://wordpress.org/wordpress-6.6-beta4.zip\">zip</a>) e contém essas correções de segurança. Para mais informações sobre a versão 6.6, confira o <a href=\"https://br.wordpress.org/2024/06/19/wordpress-6-6-beta-3/\">anúncio da versão beta 3.</a> Saiba mais sobre os <a href=\"https://make.wordpress.org/test/2024/06/03/help-test-wordpress-6-6/\">testes no WordPress 6.6 aqui</a>.</em></p>\n\n\n\n<p class=\"has-text-align-right\">Agradecemos a <a href=\"https://profiles.wordpress.org/paulkevan/\">Paul Kevan</a>, <a href=\"https://profiles.wordpress.org/ehtis/\">Ehtisham Siddiqui</a>, <a href=\"https://profiles.wordpress.org/xknown/\">Alex Concha</a>, <a href=\"https://profiles.wordpress.org/hellofromTonya\">Tonya Mork</a> e <a href=\"https://profiles.wordpress.org/angelasjin/\">Angela Jin</a> pela revisão.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3069\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"WordPress 6.6 Beta 3\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"https://br.wordpress.org/2024/06/19/wordpress-6-6-beta-3/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 19 Jun 2024 11:14:22 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:12:\"Lançamentos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.6\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3066\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:334:\"O WordPress 6.6 Beta 3 já está disponível. Esta versão beta do software WordPress está em desenvolvimento. Por favor, não instale, execute ou teste esta versão do WordPress em produção ou sites de missão crítica, você corre o risco de resultados inesperados se o fizer. Em vez disso, instale o Beta 3 em locais e [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Andre Ribeiro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7941:\"\n<p>O WordPress 6.6 Beta 3 já está disponível.</p>\n\n\n\n<p id=\"block-79834dd4-c99a-477a-b722-091806a32976\"><strong>Esta versão beta do software WordPress está em desenvolvimento. </strong>Por favor, não instale, execute ou teste esta versão do WordPress em produção ou sites de missão crítica, você corre o risco de resultados inesperados se o fizer.</p>\n\n\n\n<p id=\"block-79834dd4-c99a-477a-b722-091806a32976\">Em vez disso, instale o Beta 3 em locais e ambientes de teste usando qualquer uma dessas quatro maneiras:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><th class=\"has-text-align-center\" data-align=\"center\">Plugin</th><td>Instale e ative o plugin <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> em uma instalação do WordPress. (Selecione o canal “Bleeding edge” e o fluxo “Beta/RC Only”).</td></tr><tr><th class=\"has-text-align-center\" data-align=\"center\">Baixe diretamente</th><td>Baixe a <a href=\"https://wordpress.org/wordpress-6.6-beta3.zip\">versão Beta 3 (zip)</a> e instale-a em um site WordPress.</td></tr><tr><th class=\"has-text-align-center\" data-align=\"center\">Linha de comando</th><td>Use o comando do <a href=\"https://make.wordpress.org/cli/\">WP-CLI</a>:<br><code>wp core update --version=6.6-beta3</code></td></tr><tr><th class=\"has-text-align-center\" data-align=\"center\">WordPress Playground</th><td>Use uma <a href=\"https://playground.wordpress.net/#{%20%22preferredVersions%22:%20{%20%22php%22:%20%228.0%22,%20%22wp%22:%20%22beta%22%20},%20%22features%22:%20{%20%22networking%22:%20true%20},%20%22steps%22:%20[%20{%20%22step%22:%20%22login%22,%20%22username%22:%20%22admin%22,%20%22password%22:%20%22password%22%20},%20{%20%22step%22:%20%22importFile%22,%20%22file%22:%20{%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/wpaccessibility/a11y-theme-unit-test/master/a11y-theme-unit-test-data.xml%22%20}%20},%20{%20%22step%22:%20%22importFile%22,%20%22file%22:%20{%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/WordPress/theme-test-data/master/themeunittestdata.wordpress.xml%22%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22query-monitor%22%20},%20%22options%22:%20{%20%22activate%22:%20false%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22create-block-theme%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22debug-bar%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22health-check%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22test-reports%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22user-switching%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20}%20]%20}\">instância da versão 6.6 Beta 3 no WordPress Playground</a> para testar o software diretamente no seu navegador. Esta pode ser a maneira mais fácil, sem sites separados, sem configuração. Basta clicar e utilizar!</td></tr></tbody></table></figure>\n\n\n\n<p>A data de lançamento final programada para o WordPress 6.6 é <strong>16 de julho de 2024</strong>. Sua ajuda para testar as versões Beta e RC nas próximas quatro semanas é vital para garantir que a versão final seja tudo o que deve ser: estável, poderosa e intuitiva.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Se você encontrar um problema</h2>\n\n\n\n<p>Se você se deparar com um problema, por favor, compartilhe-o na <a href=\"https://wordpress.org/support/forum/alphabeta/\">área Alpha/Beta</a> dos fóruns de suporte. Se você estiver confortável em enviar um relatório de erros reprodutível, você pode fazê-lo <a href=\"https://core.trac.wordpress.org/newticket\">através do WordPress Trac</a>. Você também pode verificar seu problema em relação a uma lista de <a href=\"https://core.trac.wordpress.org/tickets/major\">erros conhecidos</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">A recompensa da vulnerabilidade duplica no período beta</h2>\n\n\n\n<p>A comunidade WordPress patrocina uma <a href=\"https://make.wordpress.org/security/2024/06/04/wordpress-6-6-is-coming/\">recompensa monetária por relatar novas vulnerabilidades de segurança inéditas.</a> Essa recompensa dobra durante o período entre o Beta 1 em 4 de junho e o Release Candidate final (RC) que acontecerá em 9 de julho. Por favor, siga as práticas de divulgação responsável do projeto detalhadas nesta <a href=\"https://hackerone.com/wordpress\">página do HackerOne</a> e neste <a href=\"https://wordpress.org/about/security/\">white paper de segurança</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">O trabalho continua</h2>\n\n\n\n<p><strong>Acompanhe o que há de novo na versão 6.6:</strong> <a href=\"https://br.wordpress.org/2024/06/05/wordpress-6-6-beta-1/\">confira o anúncio da versão Beta 1 para os destaques.</a></p>\n\n\n\n<p>Esta versão contempla mais de 50 atualizações para o editor, desde a versão Beta 2, incluindo 39 <a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=06%2F11%2F2024..06%2F16%2[…]id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">tíquetes para o núcleo do WordPress</a>:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/trunk?since=2024-06-08&amp;until=2024-06-16\">Tíquetes do GitHub para a versão 6.6</a> desde 11 de junho.</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?changetime=06%2F11%2F2024..06%2F16%2F2024&amp;resolution=fixed&amp;milestone=6.6&amp;max=1000&amp;col=id&amp;col=summary&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=status&amp;col=priority&amp;order=milestone\">Tíquetes fechados do Trac</a> desde 11 de junho.</li>\n</ul>\n\n\n\n<p>O ciclo Beta é focado na correção dos erros encontrados no testes da comunidade.</p>\n\n\n\n<p><strong>Você desenvolve temas?</strong> O feedback dos testes já provocou uma mudança na maneira como você oferece variações de estilo para seus usuários.</p>\n\n\n\n<p>Na versão Beta 1, se você criou variações de estilo predefinidas para o seu tema, ele gerou automaticamente um conjunto completo de opções de cores e tipos, que seus usuários poderiam misturar e combinar nas diferentes variações.</p>\n\n\n\n<p><a href=\"https://github.com/WordPress/gutenberg/pull/62469/commits/83f62ca81ff89b9d395863f6e9b7e82cec76d1b3\">No Beta 3, seu tema não gera mais essas opções automaticamente, você as gera.</a> Assim, você pode apresentar um conjunto mais simples de opções, com curadoria para orientar os esforços dos usuários para resultados mais agradáveis. <a href=\"https://github.com/WordPress/gutenberg/issues/62285\" target=\"_blank\" rel=\"noreferrer noopener\">Para mais informações sobre a lógica, veja essa discussão.</a></p>\n\n\n\n<p>Agradecemos novamente por esta contribuição muito importante para o WordPress!</p>\n\n\n\n<p class=\"has-text-align-right\"><em>Agradecemos a <a href=\"https://profiles.wordpress.org/meher/\">@meher</a>, <a href=\"https://profiles.wordpress.org/rmartinezduque/\">@rmartinezduque</a></em>, <a href=\"https://profiles.wordpress.org/atachibana/\">@a<em>tachibana</em></a> e<em> <a href=\"https://profiles.wordpress.org/mobarak/\">@mobarak</a> pela colaboração e revisão.</em></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3066\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"WordPress 6.6 Beta 2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"https://br.wordpress.org/2024/06/12/wordpress-6-6-beta-2/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 12 Jun 2024 11:52:39 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:12:\"Lançamentos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.6\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3061\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:334:\"O WordPress 6.6 Beta 2 já está disponível. Esta versão beta do software WordPress está em desenvolvimento. Por favor, não instale, execute ou teste esta versão do WordPress em produção ou sites de missão crítica, você corre o risco de resultados inesperados se o fizer. Em vez disso, instale o Beta 2 em locais e [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Andre Ribeiro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7062:\"\n<p>O WordPress 6.6 Beta 2 já está disponível.</p>\n\n\n\n<p id=\"block-79834dd4-c99a-477a-b722-091806a32976\"><strong>Esta versão beta do software WordPress está em desenvolvimento. </strong>Por favor, não instale, execute ou teste esta versão do WordPress em produção ou sites de missão crítica, você corre o risco de resultados inesperados se o fizer.</p>\n\n\n\n<p id=\"block-79834dd4-c99a-477a-b722-091806a32976\">Em vez disso, instale o Beta 2 em locais e ambientes de teste usando qualquer uma dessas quatro maneiras:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><th>Plugin</th><td>Instale e ative o plugin <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> em uma instalação do WordPress. (Selecione o canal “Bleeding edge” e o fluxo “Beta/RC Only”).</td></tr><tr><th>Baixe diretamente</th><td>Baixe a <a href=\"https://wordpress.org/wordpress-6.6-beta2.zip\">versão Beta 2 (zip)</a> e instale-a em um site WordPress.</td></tr><tr><th>Linha de comando</th><td>Use o comando do <a href=\"https://make.wordpress.org/cli/\">WP-CLI</a>:<br><code>wp core update --version=6.6-beta2</code></td></tr><tr><th>WordPress Playground</th><td>Use uma <a href=\"https://playground.wordpress.net/#{%20%22preferredVersions%22:%20{%20%22php%22:%20%228.0%22,%20%22wp%22:%20%22beta%22%20},%20%22features%22:%20{%20%22networking%22:%20true%20},%20%22steps%22:%20[%20{%20%22step%22:%20%22login%22,%20%22username%22:%20%22admin%22,%20%22password%22:%20%22password%22%20},%20{%20%22step%22:%20%22importFile%22,%20%22file%22:%20{%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/wpaccessibility/a11y-theme-unit-test/master/a11y-theme-unit-test-data.xml%22%20}%20},%20{%20%22step%22:%20%22importFile%22,%20%22file%22:%20{%20%22resource%22:%20%22url%22,%20%22url%22:%20%22https://raw.githubusercontent.com/WordPress/theme-test-data/master/themeunittestdata.wordpress.xml%22%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22query-monitor%22%20},%20%22options%22:%20{%20%22activate%22:%20false%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22create-block-theme%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22debug-bar%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22health-check%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22test-reports%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20},%20{%20%22step%22:%20%22installPlugin%22,%20%22pluginZipFile%22:%20{%20%22resource%22:%20%22wordpress.org/plugins%22,%20%22slug%22:%20%22user-switching%22%20},%20%22progress%22:%20{%20%22weight%22:%202%20}%20}%20]%20}\">instância da versão 6.6 Beta 2 no WordPress Playground</a> para testar o software diretamente no seu navegador. Esta pode ser a maneira mais fácil, sem sites separados, sem configuração. Basta clicar e utilizar!</td></tr></tbody></table></figure>\n\n\n\n<p>A data de lançamento final programada para o WordPress 6.6 é <strong>16 de julho de 2024</strong>. Sua ajuda para testar as versões Beta e RC nas próximas cinco semanas é vital para garantir que a versão final seja tudo o que deve ser: estável, poderosa e intuitiva.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Se você encontrar um problema</h2>\n\n\n\n<p>Se você se deparar com um problema, por favor, compartilhe-o na <a href=\"https://wordpress.org/support/forum/alphabeta/\">área Alpha/Beta</a> dos fóruns de suporte. Se você estiver confortável em enviar um relatório de erros reprodutível, você pode fazê-lo <a href=\"https://core.trac.wordpress.org/newticket\">através do WordPress Trac</a>. Você também pode verificar seu problema em relação a uma lista de <a href=\"https://core.trac.wordpress.org/tickets/major\">erros conhecidos</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">A recompensa da vulnerabilidade duplica no período beta</h2>\n\n\n\n<p>A comunidade WordPress patrocina uma <a href=\"https://make.wordpress.org/security/2024/06/04/wordpress-6-6-is-coming/\">recompensa monetária por relatar novas vulnerabilidades de segurança inéditas.</a> Essa recompensa dobra durante o período entre o Beta 1 em 4 de junho e o Release Candidate final (RC) que acontecerá em 9 de julho. Por favor, siga as práticas de divulgação responsável do projeto detalhadas nesta <a href=\"https://hackerone.com/wordpress\">página do HackerOne</a> e neste <a href=\"https://wordpress.org/about/security/\">white paper de segurança</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">O trabalho continua</h2>\n\n\n\n<p><strong>Acompanhe o que há de novo na versão 6.6:</strong> <a href=\"https://br.wordpress.org/2024/06/05/wordpress-6-6-beta-1/\">confira o anúncio da versão Beta 1 para mais detalhes.</a></p>\n\n\n\n<p>Esta versão contempla mais de 50 atualizações para o editor, desde a versão Beta 1, incluindo mais de 40 <a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=02%2F14%2F2024..02%2F19%2F2024&amp;milestone=6.5&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">tíquetes para núcleo do WordPress</a>:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/trunk?since=2024-06-04&amp;until=2024-06-07&amp;before=c7f51bdbe10bec0c0ab7f987a3f01caaa717c1db+70\">Tíquetes do GitHub para a versão 6.6</a> desde 4 de junho.</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?changetime=06%2F04%2F2024..06%2F11%2F2024&amp;resolution=fixed&amp;milestone=6.6&amp;max=1000&amp;col=id&amp;col=summary&amp;col=type&amp;col=milestone&amp;col=owner&amp;col=status&amp;col=priority&amp;order=priority\">Tíquetes fechados do Trac</a> desde 4 de junho.</li>\n</ul>\n\n\n\n<p>O ciclo Beta é focado na correção dos erros encontrados no testes da comunidade. Agradecemos novamente por estas contribuições de vital importância para o WordPress!</p>\n\n\n\n<p class=\"has-text-align-right\"><em>Agradecemos a <a href=\"https://profiles.wordpress.org/priethor/\">@priethor</a>, <a href=\"https://profiles.wordpress.org/dansoschin/\">@dansoschin</a>, <a href=\"https://profiles.wordpress.org/davidb/\">@davidb</a>, <a href=\"https://profiles.wordpress.org/atachibana/\">@atachibana</a>, <a href=\"https://profiles.wordpress.org/meher/\">@meher</a>, <a href=\"https://profiles.wordpress.org/webcommsat/\">@webcommsat</a> e <a href=\"https://profiles.wordpress.org/juanmaguitar/\">@juanmaguitar</a> pela revisão e colaboração.</em></p>\n\n\n\n<p></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3061\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:49:\"WordPress 6.5.4 – Atualização de manutenção\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:78:\"https://br.wordpress.org/2024/06/07/wordpress-6-5-4-atualizacao-de-manutencao/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 07 Jun 2024 11:45:54 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:12:\"Lançamentos\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.5\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://br.wordpress.org/?p=3055\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:358:\"O WordPress 6.5.4 já está disponível!Esta versão possui 5 correções de erros do núcleo. Você pode revisar um resumo das atualizações de manutenção nesta versão lendo o anúncio do release candidate. O WordPress 6.5.4 é uma versão de ciclo curto. O próximo grande lançamento será a versão 6.6 prevista para julho de 2024. Se você [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Andre Ribeiro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7519:\"\n<p><strong>O WordPress 6.5.4 já está disponível!</strong><br>Esta versão possui <a href=\"https://core.trac.wordpress.org/query?status=closed&amp;milestone=6.5.4&amp;group=status&amp;col=id&amp;col=summary&amp;col=owner&amp;col=type&amp;col=priority&amp;col=component&amp;col=version&amp;col=keywords&amp;order=priority\">5 correções de erros do núcleo</a>. Você pode revisar um resumo das atualizações de manutenção nesta versão lendo o <a href=\"https://make.wordpress.org/core/2024/05/30/wordpress-6-5-4-rc1-is-now-available/\">anúncio do release candidate</a>.</p>\n\n\n\n<p>O WordPress 6.5.4 é uma versão de ciclo curto. O próximo grande lançamento será a <a href=\"https://make.wordpress.org/core/6-6/\">versão 6.6</a> prevista para julho de 2024.</p>\n\n\n\n<p>Se você tiver sites que suportam atualizações automáticas em segundo plano, o processo de atualização será iniciado automaticamente.</p>\n\n\n\n<p>Você pode <a href=\"https://wordpress.org/wordpress-6.5.4.zip\">baixar o WordPress 6.5.4 do WordPress.org</a> ou visitar seu Painel do WordPress, clicar em “Atualizações” e clicar em “Atualizar agora”.</p>\n\n\n\n<p>Para mais informações sobre esta versão, visite <a href=\"https://wordpress.org/support/wordpress-version/version-6-5-4\">o site HelpHub</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Agradecimento aos colaboradores</h2>\n\n\n\n<p>Este lançamento foi liderado por <a href=\"https://profiles.wordpress.org/hellofromTonya\">Tonya Mork</a>, <a href=\"https://profiles.wordpress.org/costdev\">Colin Stewart</a> e <a href=\"https://profiles.wordpress.org/jorbin\">Aaron Jorbin</a>.</p>\n\n\n\n<p>O WordPress 6.5.4 não teria sido possível sem as contribuições das pessoas a seguir. Suas contribuições para fornecer correções de manutenção em uma versão estável é uma prova do poder e capacidade da comunidade WordPress.</p>\n\n\n\n<p><a href=\"https://profiles.wordpress.org/jorbin\">Aaron Jorbin</a>, <a href=\"https://profiles.wordpress.org/adamsilverstein\">Adam Silverstein</a>, <a href=\"https://profiles.wordpress.org/adrianduffell\">adrianduffell</a>, <a href=\"https://profiles.wordpress.org/wildworks\">Aki Hamano</a>, <a href=\"https://profiles.wordpress.org/alanfuller\">Alan Fuller</a>, <a href=\"https://profiles.wordpress.org/anlino\">Anders Norén</a>, <a href=\"https://profiles.wordpress.org/oandregal\">André</a>, <a href=\"https://profiles.wordpress.org/afercia\">Andrea Fercia</a>, <a href=\"https://profiles.wordpress.org/azaozz\">Andrew Ozz</a>, <a href=\"https://profiles.wordpress.org/andrewserong\">Andrew Serong</a>, <a href=\"https://profiles.wordpress.org/afragen\">Andy Fragen</a>, <a href=\"https://profiles.wordpress.org/annezazu\">annezazu</a>, <a href=\"https://profiles.wordpress.org/dextorlobo\">Arun Sharma</a>, <a href=\"https://profiles.wordpress.org/aslamdoctor\">Aslam Doctor</a>, <a href=\"https://profiles.wordpress.org/benlk\">Ben Keith</a>, <a href=\"https://profiles.wordpress.org/britner\">Ben Ritner – Kadence WP</a>, <a href=\"https://profiles.wordpress.org/bernhard-reiter\">bernhard-reiter</a>, <a href=\"https://profiles.wordpress.org/ironprogrammer\">Brian Alexander</a>, <a href=\"https://profiles.wordpress.org/poena\">Carolina Nymark</a>, <a href=\"https://profiles.wordpress.org/costdev\">Colin Stewart</a>, <a href=\"https://profiles.wordpress.org/CookiesForDevo\">CookiesForDevo</a>, <a href=\"https://profiles.wordpress.org/colorful-tones\">Damon Cook</a>, <a href=\"https://profiles.wordpress.org/talldanwp\">Daniel Richards</a>, <a href=\"https://profiles.wordpress.org/darerodz\">darerodz</a>, <a href=\"https://profiles.wordpress.org/davecpage\">Dave Page</a>, <a href=\"https://profiles.wordpress.org/davidbaumwald\">David Baumwald</a>, <a href=\"https://profiles.wordpress.org/justlevine\">David Levine</a>, <a href=\"https://profiles.wordpress.org/DrewAPicture\">Drew Jaynes</a>, <a href=\"https://profiles.wordpress.org/ellatrix\">Ella</a>, <a href=\"https://profiles.wordpress.org/kebbet\">Erik</a>, <a href=\"https://profiles.wordpress.org/evanltd\">evanltd</a>, <a href=\"https://profiles.wordpress.org/flixos90\">Felix Arntz</a>, <a href=\"https://profiles.wordpress.org/mamaduka\">George Mamadashvili</a>, <a href=\"https://profiles.wordpress.org/grantmkin\">Grant M. Kinney</a>, <a href=\"https://profiles.wordpress.org/gziolo\">Greg Ziółkowski</a>, <a href=\"https://profiles.wordpress.org/isabel_brison\">Isabel Brison</a>, <a href=\"https://profiles.wordpress.org/macmanx\">James Huff</a>, <a href=\"https://profiles.wordpress.org/jason_the_adams\">Jason Adams</a>, <a href=\"https://profiles.wordpress.org/audrasjb\">Jb Audras</a>, <a href=\"https://profiles.wordpress.org/JeffPaul\">Jeffrey Paul</a>, <a href=\"https://profiles.wordpress.org/jeherve\">Jeremy Herve</a>, <a href=\"https://profiles.wordpress.org/luminuu\">Jessica Lyschik</a>, <a href=\"https://profiles.wordpress.org/joedolson\">Joe Dolson</a>, <a href=\"https://profiles.wordpress.org/joemcgill\">Joe McGill</a>, <a href=\"https://profiles.wordpress.org/jordesign\">jordesign</a>, <a href=\"https://profiles.wordpress.org/jorgefilipecosta\">Jorge Costa</a>, <a href=\"https://profiles.wordpress.org/verygoode\">Joshua Goode</a>, <a href=\"https://profiles.wordpress.org/kevin940726\">Kai Hao</a>, <a href=\"https://profiles.wordpress.org/kevinwhoffman\">Kevin Hoffman</a>, <a href=\"https://profiles.wordpress.org/khokansardar\">Khokan Sardar</a>, <a href=\"https://profiles.wordpress.org/luisherranz\">luisherranz</a>, <a href=\"https://profiles.wordpress.org/mmaattiiaass\">Matias Benedetto</a>, <a href=\"https://profiles.wordpress.org/webdevmattcrom\">Matt Cromwell</a>, <a href=\"https://profiles.wordpress.org/devsahadat\">Md Sahadat Husain</a>, <a href=\"https://profiles.wordpress.org/mukesh27\">Mukesh Panchal</a>, <a href=\"https://profiles.wordpress.org/narenin\">Narendra Sishodiya</a>, <a href=\"https://profiles.wordpress.org/ntsekouras\">Nik Tsekouras</a>, <a href=\"https://profiles.wordpress.org/swissspidy\">Pascal Birchler</a>, <a href=\"https://profiles.wordpress.org/peterwilsoncc\">Peter Wilson</a>, <a href=\"https://profiles.wordpress.org/ramonopoly\">ramonopoly</a>, <a href=\"https://profiles.wordpress.org/roytanck\">Roy Tanck</a>, <a href=\"https://profiles.wordpress.org/salcode\">Sal Ferrarello</a>, <a href=\"https://profiles.wordpress.org/mikachan\">Sarah Norris</a>, <a href=\"https://profiles.wordpress.org/SergeyBiryukov\">Sergey Biryukov</a>, <a href=\"https://profiles.wordpress.org/sabernhardt\">Stephen Bernhardt</a>, <a href=\"https://profiles.wordpress.org/stevejonesdev\">Steve Jones</a>, <a href=\"https://profiles.wordpress.org/tomjcafferkey\">Tom Cafferkey</a>, <a href=\"https://profiles.wordpress.org/nestea29950\">WilliamG</a> e <a href=\"https://profiles.wordpress.org/yguyon\">Yannis Guyon</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Como contribuir</h2>\n\n\n\n<p>Para se envolver no desenvolvimento do núcleo do WordPress, dirija-se ao Trac, <a href=\"https://core.trac.wordpress.org/report/6\">escolha um ticket</a> e participe da conversa nos canais <a href=\"https://wordpress.slack.com/archives/C02RQBWTW\">#core</a> e <a href=\"https://wordpress.slack.com/archives/C06U06K50Q5\">#6-6-release-leads</a>. Precisa de ajuda? Confira o <a href=\"https://make.wordpress.org/core/handbook/\">Manual do colaborador do núcleo</a>.</p>\n\n\n\n<p class=\"has-text-align-right\"><em>Agradecemos a <a href=\"https://profiles.wordpress.org/afragen/\">@afragen</a>, <a href=\"https://profiles.wordpress.org/hellofromtonya/\">@hellofromtonya</a> e </em><a href=\"https://profiles.wordpress.org/angelasjin/\">@<em>angelasjin</em></a><em> pela revisão.</em></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"3055\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:35:\"https://br.wordpress.org/news/feed/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:44:\"http://purl.org/rss/1.0/modules/syndication/\";a:2:{s:12:\"updatePeriod\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"\n	hourly	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:15:\"updateFrequency\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"\n	1	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:4:\"site\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"13096052\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";O:48:\"WpOrg\\Requests\\Utility\\CaseInsensitiveDictionary\":1:{s:7:\"\0*\0data\";a:11:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Fri, 09 Aug 2024 11:59:29 GMT\";s:12:\"co